static void _cbDialog(WM_MESSAGE * pMsg) {
  WM_HWIN hItem;
  // USER START (Optionally insert additional variables)
  // USER END

  switch (pMsg->MsgId) {
  case WM_INIT_DIALOG:
    //
    // Initialization of 'play_view'
    //
    hItem = pMsg->hWin;
    FRAMEWIN_SetTitleVis(hItem, 0);
    //
    // Initialization of 'time'
    //
    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_5);
    TEXT_SetTextAlign(hItem, GUI_TA_HCENTER | GUI_TA_VCENTER);
    //
    // Initialization of 'cur'
    //
    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_6);
    TEXT_SetTextAlign(hItem, GUI_TA_HCENTER | GUI_TA_VCENTER);
    // USER START (Optionally insert additional code for further widget initialization)
    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_1);
    TEXT_SetTextAlign(hItem, GUI_TA_HCENTER | GUI_TA_VCENTER);
    TEXT_SetText(hItem, (char *)audio_info_buffer.volbuf);


    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_0); 
    TEXT_SetText(hItem, (char *)g_ui_ctx.audio_info.filename);
    TEXT_SetFont(hItem, GUI_FONT_16_ASCII); 

    hItem = WM_GetDialogItem(pMsg->hWin, ID_PROGBAR_0); 
    PROGBAR_SetText(hItem, " ");
    PROGBAR_SetMinMax(hItem, 0, 100); 
    PROGBAR_SetBarColor(hItem, 0, GUI_YELLOW);
    PROGBAR_SetBarColor(hItem, 0, GUI_WHITE);

    hItem = WM_GetDialogItem(pMsg->hWin, ID_PROGBAR_1); 
    PROGBAR_SetText(hItem, " ");
    PROGBAR_SetMinMax(hItem, 0, 40); 
    PROGBAR_SetBarColor(hItem, 0, GUI_YELLOW);
    PROGBAR_SetBarColor(hItem, 0, GUI_WHITE);
    PROGBAR_SetValue(hItem, g_play_ctx.ucvolume);
    // USER END
    break;
  // USER START (Optionally insert additional message handling)
  case WM_SELECT_WINDOW:
    
     WM_HideWindow(pMsg->hWin);
     WM_ShowWindow(g_page[1]);
     WM_SetFocus(WM_GetDialogItem(g_page[1], ID_LISTVIEW_0));
    break;

  case WM_PAINT:
    break;
  case WM_REFRESH_PLAY_TIME:

    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_7);
    TEXT_SetText(hItem, (char *)audio_info_buffer.rtc_time);

    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_5);
    TEXT_SetText(hItem, (char *)audio_info_buffer.allsecbuf);

    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_6);
    TEXT_SetText(hItem, (char *)audio_info_buffer.cursecbuf);

    hItem = WM_GetDialogItem(pMsg->hWin, ID_PROGBAR_0); 
    PROGBAR_SetValue(hItem, g_ui_ctx.audio_info.cur_sec * 100 / g_ui_ctx.audio_info.all_sec);

    break;
  case WM_REFRESH_PLAY_INFO:
    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_0);
    TEXT_SetText(hItem, (char *)g_ui_ctx.audio_info.filename);

    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_2);
    TEXT_SetText(hItem, (char *)audio_info_buffer.bitratebuf);

    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_3);
    TEXT_SetText(hItem, (char *)audio_info_buffer.sampratebuf);

    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_4);
    TEXT_SetText(hItem, (char *)audio_info_buffer.channelbuf);
    break;
  case WM_VOL_CTRL:
    hItem = WM_GetDialogItem(pMsg->hWin, ID_TEXT_1);
    TEXT_SetText(hItem, (char *)audio_info_buffer.volbuf);

    hItem = WM_GetDialogItem(pMsg->hWin, ID_PROGBAR_1); 
    PROGBAR_SetValue(hItem, g_play_ctx.ucvolume);

    break;
  // USER END
  default:
    WM_DefaultProc(pMsg);
    break;
  }
}

